// Get all input items
const items = $input.all();

let aiText = '';
let attachments = [];

// Loop through items to find AI text and binary files
for (const item of items) {

  // ---- Extract AI text ----
  if (Array.isArray(item.json?.content)) {
    // Case like input1
    aiText = item.json.content[0]?.text || aiText;
  } else if (Array.isArray(item.json?.output)) {
    // Case like input2
    aiText = item.json.output[0]?.content[0]?.text || aiText;
  } else if (Array.isArray(item.json) && Array.isArray(item.json[0]?.content)) {
    // Sometimes input comes nested
    aiText = item.json[0].content[0]?.text || aiText;
  }

  // ---- Extract attachments metadata ----
  if (item.binary && Object.keys(item.binary).length > 0) {
    for (const [key, b] of Object.entries(item.binary)) {
      attachments.push({
        key,                         // attachment_0, attachment_1, etc.
        fileName: b.fileName || null,
        mimeType: b.mimeType || null,
        fileSize: b.fileSize || null,
        fileExtension: b.fileExtension || null,
        id: b.id || null,
        url: b.url || b.filePath || null
      });
    }
  }
}

// ---- Find the email item ----
const emailItem = items.find(i => typeof i.json?.message_text === 'string');

// ---- Build unified output ----
const output = emailItem ? {
  ...emailItem.json,
  attachment_text_details: aiText,
  image_details: '',       // keep if you want separate image description
  attachments,
  attachment_count: attachments.length,
  has_attachments: attachments.length > 0
} : {
  attachment_text_details: aiText,
  attachments,
  attachment_count: attachments.length,
  has_attachments: attachments.length > 0,
  key:$('HTTP Request1').first().json.Key,
  id:$('HTTP Request1').first().json.Id
};

return [{ json: output }];

