const items = $input.all();
const newItems = [];

for (const item of items) {

  const binaryKeys = item.binary ? Object.keys(item.binary) : [];
  const attachmentKeys = binaryKeys.filter(key => key.startsWith('attachment_'));

  // If no attachments → optionally return original item (or skip)
  if (attachmentKeys.length === 0) {
    newItems.push({
      json: {
        ...item.json,
        document_labels: null
      },
      binary: {}
    });
    continue;
  }

  // Create one output item per attachment
  for (const key of attachmentKeys) {
    newItems.push({
      json: {
        ...item.json,
        document_labels: key
      },
      binary: {
        [key]: item.binary[key]
      }
    });
  }
}

return newItems;
